head.script:
scwin.statusFlag = "";
scwin.processFlag = "";
scwin.v_contractno = "";
scwin.tabIndex = 0;

scwin.v_linkcheck = "";
scwin.v_kcomcd = "";
scwin.v_blno = "";
scwin.v_mhno = "";
scwin.v_bkno = "";

scwin.vLobranCd = "";
scwin.vLobranNm = "";

scwin.hd_kcomcd = "DBEX";
scwin.hd_bkbltype = "C";
scwin.ed_groupNo = "";
scwin.hd_bkIo = "O";

scwin.vCurDate = "";
scwin.currentTime = "";
scwin.userId = "";
scwin.userNm = "";

scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    let now = new Date();
    let hof = String(now.getHours()).padStart(2, "0");
    let mm = String(now.getMinutes()).padStart(2, "0");
    scwin.currentTime = hof + mm;

    scwin.userId = $c.ses.getUserId();
    scwin.userNm = $c.ses.getUserNm();
    scwin.vLobranCd = $c.ses.getLobranCd();
    scwin.vLobranNm = $c.ses.getLobranNm();

    scwin.params = $c.data.getParameter();
    if (scwin.params != null) {
        scwin.v_linkcheck = scwin.params["linkcheck"] || "0";
        scwin.v_kcomcd = scwin.params["kcomcd"] || "";
        scwin.v_blno = scwin.params["blno"] || "";
        scwin.v_mhno = scwin.params["mhno"] || "";
        scwin.v_bkno = scwin.params["bkno"] || "";
    } else {
        scwin.v_linkcheck = "0";
    }

    scwin.f_DefaultValue();
    scwin.f_Check();
    scwin.f_ContainerTypeLoading();
    scwin.f_getParametrSetting(scwin.v_linkcheck);
};

scwin.onUdcCompleted = function() {
};

scwin.f_getParametrSetting = function(gubun) {
    switch (gubun) {
        case "0":
            break;
        case "1":
            let lv_kcomcd = scwin.v_kcomcd;
            let lv_bkno = scwin.v_bkno;
            if (lv_bkno == "null" || lv_bkno == "") {
                cnd_ed_bkNo.setValue("");
                cnd_ed_bkNo.setFocus();
                return false;
            }
            scwin.hd_kcomcd = lv_kcomcd;
            cnd_ed_bkNo.setValue(lv_bkno);
            scwin.f_Retrieve();
            break;
    }
};

scwin.f_Check = function() {
    ed_cnttype1.setValue("22GP");
    ed_cnttype2.setValue("42GP");
    ed_cnttype3.setValue("45GP");
    lc_cfs.setValue("F");
    chb_iptYn.setValue("");
    chb_triYn.setValue("");
};

scwin.f_DefaultValue = function() {
    scwin.f_initSetTab();
    scwin.f_Set("INIT");
    cnd_ed_bkNo.setFocus();
    scwin.processFlag = "T";
};

scwin.f_initSetTab = function() {
    $c.gus.cfEnableObjects([btn_Find, btn_HouseBl, btn_DirectBl]);
    // TODO: cfViewTab(0) - tab control
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Cancel, btn_Save, btn_Delete, btn_Update, btn_Print, btn_HouseBl, btn_DirectBl,
                btn_OrderSendDel, btn_OrderSend, btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Find]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfEnableObjects([cnd_ed_bkNo]);
            scwin.statusFlag = "I";
            break;
        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
            $c.gus.cfEnableBtnOnly([btn_Copy, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_Find, btn_HouseBl, btn_DirectBl]);
            gr_containerDoorOrder.setColumnVisible("chk", true);
            gr_containerDoorOrderQty.setReadOnly("grid", true);
            gr_containerBookingCont.setReadOnly("grid", true);
            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }
            $c.gus.cfEnableObjects([cnd_ed_bkNo]);
            scwin.statusFlag = "";
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Copy, btn_Create, btn_Update, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_DirectBl]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_Find,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
            gr_containerDoorOrder.setColumnVisible("chk", false);
            gr_containerDoorOrderQty.setReadOnly("grid", false);
            gr_containerBookingCont.setReadOnly("grid", false);
            $c.gus.cfDisableObjects([cnd_ed_bkNo]);
            scwin.statusFlag = "C";
            break;
        case "UPDATE":
            dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
            dma_retrieve.set("bkNo", ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "bkNo"));
            dma_retrieve.set("seq", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));
            $c.sbm.execute(sbm_retrievebookingHbl);

            if (ds_bookingHbl.getCellData(ds_bookingHbl.getRowPosition(), "hblno") == "" || ds_bookingHbl.getRowCount() == 0) {
                $c.gus.cfDisableBtnOnly([btn_Copy, btn_Update, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_DirectBl]);
                $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_Find,
                    btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
                $c.gus.cfDisableKey();
                scwin.f_EnablePopUpObj();
                gr_containerDoorOrder.setColumnVisible("chk", false);
                gr_containerDoorOrderQty.setReadOnly("grid", false);
                gr_containerBookingCont.setReadOnly("grid", false);
                $c.gus.cfDisableObjects([cnd_ed_bkNo]);
                scwin.statusFlag = "U";
            } else {
                $c.gus.cfDisableBtnOnly([btn_Copy, btn_Update, btn_Create, btn_Delete, btn_Print, btn_OrderSendDel, btn_OrderSend, btn_HouseBl, btn_DirectBl]);
                $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_Find,
                    btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_CntrReceive, btn_AddRow3, btn_DelRow3, btn_CancelRow3]);
                $c.gus.cfDisableKeyData();
                scwin.f_DisablePopUpObj2();
                $c.gus.cfEnableObjects([chb_triYn, lc_triItemType, ed_triWrkDesc, txt_bkPicNm,
                    ed_ts1VsslCd, txt_ts1VsslNm, ed_ts2VsslCd, txt_ts2VsslNm, ed_ts1Voy,
                    ed_ts2Voy, ed_ts1PortCd, txt_ts1PortNm, ed_ts2PortCd, txt_ts2PortNm,
                    ica_ts1Etd, ica_ts1Eta, ica_ts2Etd, ica_ts2Eta, txt_remarkMaster,
                    ed_refSellingAmt, ed_refBuyingAmt, ed_freeDay]);
                gr_containerDoorOrder.setReadOnly("grid", true);
                gr_containerDoorOrderQty.setReadOnly("grid", true);
                gr_containerBookingCont.setReadOnly("grid", true);
                $c.gus.cfDisableObjects([cnd_ed_bkNo]);
                scwin.statusFlag = "U";
            }
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel, btn_Print]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_EnablePopUpObj = function() {
    // TODO: Enable popup image objects
};

scwin.f_DisablePopUpObj = function() {
    // TODO: Disable popup image objects
};

scwin.f_DisablePopUpObj2 = function() {
    // TODO: Disable popup image objects after B/L issue
};

scwin.f_selectTabMenu = function(idx) {
    switch (idx) {
        case 0:
            scwin.tabIndex = 0;
            break;
        case 1:
            scwin.tabIndex = 1;
            if (ds_containerDoorOrder.getRowCount() == 0) {
                scwin.f_autoCreateDoorOrderInfo();
            }
            break;
    }
};

scwin.f_Retrieve = async function() {
    if (cnd_ed_bkNo.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056, ["Booking No"]);
        return;
    } else {
        dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
        dma_retrieve.set("bkNo", cnd_ed_bkNo.getValue());
        dma_retrieve.set("bkbltype", scwin.hd_bkbltype);
        await $c.sbm.execute(sbm_retrieve);
        cnd_ed_bkNo.setFocus();
    }
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(cnd_ed_bkNo);
};

scwin.f_Create = function() {
    scwin.f_Set("CREATE");
    cnd_ed_bkNo.setValue("");
    ds_containerBookingList.insertRow();
    ds_containerDoorOrder.removeAll();
    ds_containerDoorOrderQty.removeAll();
    ds_containerBookingCont.removeAll();
    ds_houseblList.removeAll();
    scwin.f_Check();
    let row = ds_containerBookingList.getRowPosition();
    ds_containerBookingList.setCellData(row, "reDt", scwin.vCurDate);
    ds_containerBookingList.setCellData(row, "bkPic", scwin.userId);
    ds_containerBookingList.setCellData(row, "bkPicNm", scwin.userNm);
    if (!(scwin.vLobranCd == "null" || scwin.vLobranCd == null || scwin.vLobranCd == "")) {
        ds_containerBookingList.setCellData(row, "dept", scwin.vLobranCd);
        ds_containerBookingList.setCellData(row, "deptnm", scwin.vLobranNm);
    }
    ds_containerBookingList.setCellData(row, "etRsltsDt", "");
};

scwin.f_Update = async function() {
    let row = ds_containerBookingList.getRowPosition();
    if (row < 0 || ds_containerBookingList.getCellData(row, "bkNo") == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["HEADER"]);
        return;
    } else {
        scwin.f_Set("UPDATE");
    }
};

scwin.f_Save = async function() {
    if (ds_containerBookingList.isUpdated() || ds_containerDoorOrder.isUpdated() || ds_containerDoorOrderQty.isUpdated() || ds_containerBookingCont.isUpdated()) {
        if (await scwin.f_validate()) {
            let chk = await $c.win.confirm(E_MSG_CM_CRM_001);
            if (chk) {
                let bkRow = ds_containerBookingList.getRowPosition();
                if (ds_containerBookingList.getCellData(bkRow, "bkNo") == "") {
                    if (ds_containerBookingList.getCellData(bkRow, "bkPic") == "" && ds_containerBookingList.getCellData(bkRow, "docPic") == "") {
                        await $c.win.alert("Booking담당자/Doc담당자 중 한 가지는 필수로 입력하여야 합니다.");
                        return false;
                    }
                    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
                    if (ds_containerBookingList.getCellData(bkRow, "etRsltsDt") == "") {
                        dma_retrieve.set("bkEtd", ds_containerBookingList.getCellData(bkRow, "bkEtd"));
                        ds_containerBookingList.setCellData(bkRow, "etRsltsDt", ds_containerBookingList.getCellData(bkRow, "bkEtd"));
                    } else {
                        dma_retrieve.set("bkEtd", ds_containerBookingList.getCellData(bkRow, "etRsltsDt"));
                    }
                    if (ds_containerBookingList.getCellData(bkRow, "bkPic") == "") {
                        ds_containerBookingList.setCellData(bkRow, "bkPic", scwin.userId);
                        ds_containerBookingList.setCellData(bkRow, "bkPicNm", scwin.userNm);
                    }
                    await $c.sbm.execute(sbm_retrievebookingNo);
                    let noRow = ds_retrieveNo.getRowPosition();
                    if (noRow >= 0) {
                        ds_containerBookingList.setCellData(bkRow, "bkNo", ds_retrieveNo.getCellData(noRow, "bkNo"));
                    }
                }
                dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
                dma_retrieve.set("bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
                dma_retrieve.set("seq", ds_containerDoorOrder.getRowCount() > 0 ? ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq") : "");
                await $c.sbm.execute(sbm_retrievebookingHbl);

                if (ds_bookingHbl.getCellData(ds_bookingHbl.getRowPosition(), "hblno") == "" || ds_bookingHbl.getRowCount() == 0) {
                    ds_containerBookingList.setCellData(bkRow, "kcomcd", scwin.hd_kcomcd);
                    ds_containerBookingList.setCellData(bkRow, "bkbltype", scwin.hd_bkbltype);
                    ds_containerBookingList.setCellData(bkRow, "bkEtd", ed_bkEtd.getValue());
                    ds_containerBookingList.setCellData(bkRow, "inpid", scwin.userId);
                    if (ds_containerDoorOrder.getRowCount() == 0) {
                        scwin.f_autoCreateDoorOrderInfo();
                    } else {
                        let dqRow = ds_containerDoorOrderQty.getRowPosition();
                        if (dqRow >= 0) ds_containerDoorOrderQty.setCellData(dqRow, "bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
                        let doRow = ds_containerDoorOrder.getRowPosition();
                        if (doRow >= 0) ds_containerDoorOrder.setCellData(doRow, "bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
                    }
                    await $c.sbm.execute(sbm_save);
                } else {
                    await $c.sbm.execute(sbm_save);
                }
                scwin.f_Set("SAVE");
                cnd_ed_bkNo.setValue(ds_containerBookingList.getCellData(bkRow, "bkNo"));
                scwin.f_Retrieve();
            }
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Container Booking"]);
    }
};

scwin.f_Cancel = function() {
    if (scwin.statusFlag == "C") {
        scwin.f_Set("INIT");
    } else {
        scwin.f_Set("RETRIEVE");
        ds_containerBookingList.undoAll();
        ds_ctrtNo.undoAll();
        scwin.f_cancelRow(1);
        scwin.f_cancelRow(2);
        scwin.f_cancelRow(3);
        cnd_ed_bkNo.setFocus();
        scwin.processFlag = "T";
    }
};

scwin.f_autoCreateDoorOrderInfo = function() {
    ds_containerDoorOrder.insertRow();
    ds_containerDoorOrderQty.insertRow();
    let doRow = ds_containerDoorOrder.getRowPosition();
    ds_containerDoorOrder.setCellData(doRow, "kcomcd", scwin.hd_kcomcd);
    let bkRow = ds_containerBookingList.getRowPosition();
    ds_containerDoorOrder.setCellData(doRow, "bkNo", bkRow >= 0 ? ds_containerBookingList.getCellData(bkRow, "bkNo") : "");
    ds_containerDoorOrder.setCellData(doRow, "doordt", scwin.vCurDate + scwin.currentTime);
    ds_containerDoorOrder.setCellData(doRow, "bkdoorseq", "01");
    ds_containerDoorOrder.setCellData(doRow, "internalTyp", "2");
    ds_containerDoorOrder.setCellData(doRow, "transcd", "109856");
    ds_containerDoorOrder.setCellData(doRow, "inpid", scwin.userId);

    let dqRow = ds_containerDoorOrderQty.getRowPosition();
    ds_containerDoorOrderQty.setCellData(dqRow, "kcomcd", scwin.hd_kcomcd);
    ds_containerDoorOrderQty.setCellData(dqRow, "bkNo", bkRow >= 0 ? ds_containerBookingList.getCellData(bkRow, "bkNo") : "");
    ds_containerDoorOrderQty.setCellData(dqRow, "bkdoorseq", "01");
    if (lc_cfs.getValue() == "F") {
        ds_containerDoorOrderQty.setCellData(dqRow, "qtytype", "22GP");
        ds_containerDoorOrderQty.setCellData(dqRow, "realQtytype", "22GP");
    } else if (lc_cfs.getValue() == "L") {
        ds_containerDoorOrderQty.setCellData(dqRow, "qtytype", "R/T");
        ds_containerDoorOrderQty.setCellData(dqRow, "realQtytype", "R/T");
    }
    scwin.f_doorTypeQtyLoading(dqRow, "qtytype");
    ds_containerDoorOrderQty.setCellData(dqRow, "inpid", scwin.userId);
};

scwin.f_Copy = function() {
    scwin.f_Set("CREATE");
    cnd_ed_bkNo.setValue("");
    ds_containerDoorOrder.removeAll();
    ds_containerDoorOrderQty.removeAll();
    ds_containerBookingCont.removeAll();
    ds_houseblList.removeAll();
    ds_ctrtNo.removeAll();
    scwin.f_Check();
    let bkRow = ds_containerBookingList.getRowPosition();
    if (bkRow >= 0 && ds_containerBookingList.getRowCount() > 0) {
        ds_containerBookingList.setRowStatus(bkRow, "C");
    }
    if (bkRow >= 0) {
        ds_containerBookingList.setCellData(bkRow, "bkNo", "");
        ds_containerBookingList.setCellData(bkRow, "custCd", "");
        ds_containerBookingList.setCellData(bkRow, "custNm", "");
        ds_containerBookingList.setCellData(bkRow, "docPic", "");
        ds_containerBookingList.setCellData(bkRow, "docPicNm", "");
        ds_containerBookingList.setCellData(bkRow, "cargoPic", "");
        ds_containerBookingList.setCellData(bkRow, "cargoPicNm", "");
    }
};

scwin.f_Delete = async function() {
    let errorChk = 0;
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "sendDt") != "") {
            await $c.win.alert("Order sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
            errorChk = 1;
        }
    }
    if (errorChk == 1) return;

    dma_retrieve.set("kcomcd", scwin.hd_kcomcd);
    dma_retrieve.set("bkNo", ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "bkNo"));
    dma_retrieve.set("seq", "");
    await $c.sbm.execute(sbm_retrievebookingHbl);
    let hblRow = ds_bookingHbl.getRowPosition();
    if (hblRow >= 0 && ds_bookingHbl.getCellData(hblRow, "hblno") != "undefined" && ds_bookingHbl.getRowCount() != 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["House B/L", "delete"]);
        return;
    }

    let chk = await $c.win.confirm(E_MSG_CM_CRM_004);
    if (chk) {
        for (let i = ds_containerBookingList.getRowCount() - 1; i >= 0; i--) {
            ds_containerBookingList.removeRow(i);
        }
        await $c.sbm.execute(sbm_delete);
        cnd_ed_bkNo.setValue("");
        ds_containerBookingList.removeAll();
        ds_containerDoorOrder.removeAll();
        ds_containerDoorOrderQty.removeAll();
        ds_containerBookingCont.removeAll();
        ds_houseblList.removeAll();
        scwin.f_Set("INIT");
        cnd_ed_bkNo.setValue("");
    }
};

scwin.f_orderSend = async function() {
    let doRow = ds_containerDoorOrder.getRowPosition();
    if (doRow < 0) return;
    if (ds_containerDoorOrder.getCellData(doRow, "internalTyp") == "1") {
        let bkRow = ds_containerBookingList.getRowPosition();
        if (bkRow >= 0 && ds_containerBookingList.getCellData(bkRow, "itemCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]);
            return;
        }
        let errorChk = 0;
        let j = 0;
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                j = j + 1;
            }
        }
        if (j == 0) errorChk = 1;

        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                let lv_kcomcd = scwin.hd_kcomcd;
                let v_orderno = ds_containerDoorOrder.getCellData(i, "bkNo");
                let v_seq = ds_containerDoorOrder.getCellData(i, "bkdoorseq");
                // TODO: ds_doorOrderQtyCheck dynamic loading
                // ds_doorOrderQtyCheck check logic
            }
        }

        if (errorChk == 0) {
            for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
                if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                    ds_containerDoorOrder.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
                        ds_containerDoorOrder.setCellData(i, "orderType", 1);
                    } else {
                        ds_containerDoorOrder.setCellData(i, "orderType", 2);
                    }
                    ds_containerDoorOrder.setCellData(i, "inpid", scwin.userId);
                }
            }
            await $c.sbm.execute(sbm_saveOrderSend);
            scwin.f_Retrieve();
        }
    } else {
        await $c.win.alert("Normal Type");
        return;
    }
};

scwin.f_orderSendDel = async function() {
    let doRow = ds_containerDoorOrder.getRowPosition();
    if (doRow < 0) return;
    if (ds_containerDoorOrder.getCellData(doRow, "internalTyp") == "1") {
        let errorChk = 0;
        let j = 0;
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                j = j + 1;
            }
        }
        if (j == 0) errorChk = 1;

        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
                    await $c.win.alert("Order is not sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
                    errorChk = 1;
                }
            }
        }

        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                if (ds_containerDoorOrder.getCellData(i, "mcomOdrNo") != "") {
                    await $c.win.alert("Order sended : Order No -> " + ds_containerDoorOrder.getCellData(i, "bkNo") + ",Seq -> " + ds_containerDoorOrder.getCellData(i, "bkdoorseq"));
                    errorChk = 1;
                }
            }
        }

        if (errorChk == 0) {
            for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
                if (ds_containerDoorOrder.getCellData(i, "chk") == "T") {
                    ds_containerDoorOrder.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    ds_containerDoorOrder.setCellData(i, "orderType", 3);
                    ds_containerDoorOrder.setCellData(i, "inpid", scwin.userId);
                }
            }
            await $c.sbm.execute(sbm_saveOrderSend);
            scwin.f_Retrieve();
        }
    } else {
        await $c.win.alert("Normal Type");
        return;
    }
};

scwin.f_addRow = async function(disGubun) {
    let bkRow = ds_containerBookingList.getRowPosition();
    switch (disGubun) {
        case 1:
            if (bkRow < 0 || ds_containerBookingList.getCellData(bkRow, "bkNo") == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);
            } else {
                ds_containerDoorOrder.insertRow();
                let doRow = ds_containerDoorOrder.getRowPosition();
                let v_seq = String(doRow + 1);
                let v_seqResult = $c.str.lpad(v_seq, "0", 2);
                ds_containerDoorOrder.setCellData(doRow, "bkdoorseq", v_seqResult);
                ds_containerDoorOrder.setCellData(doRow, "kcomcd", scwin.hd_kcomcd);
                ds_containerDoorOrder.setCellData(doRow, "bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
                ds_containerDoorOrder.setCellData(doRow, "internalTyp", "1");
                ds_containerDoorOrder.setCellData(doRow, "inpid", scwin.userId);
                ds_containerDoorOrder.setCellData(doRow, "doordt", scwin.vCurDate + scwin.currentTime);
                gr_containerDoorOrder.setFocusedCell(doRow, "doordt");
            }
            break;
        case 2:
            if (bkRow < 0 || ds_containerBookingList.getCellData(bkRow, "bkNo") == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);
            } else {
                let doRow2 = ds_containerDoorOrder.getRowPosition();
                if (doRow2 < 0 || ds_containerDoorOrder.getCellData(doRow2, "bkdoorseq") == "" || ds_containerDoorOrder.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Booking Door Order"]);
                } else {
                    ds_containerDoorOrderQty.insertRow();
                    let dqRow = ds_containerDoorOrderQty.getRowPosition();
                    ds_containerDoorOrderQty.setCellData(dqRow, "kcomcd", scwin.hd_kcomcd);
                    ds_containerDoorOrderQty.setCellData(dqRow, "bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
                    ds_containerDoorOrderQty.setCellData(dqRow, "bkdoorseq", ds_containerDoorOrder.getCellData(doRow2, "bkdoorseq"));
                    ds_containerDoorOrderQty.setCellData(dqRow, "inpid", scwin.userId);
                    gr_containerDoorOrderQty.setFocusedCell(dqRow, "qtytype");
                }
            }
            break;
        case 3:
            if (bkRow < 0 || ds_containerBookingList.getCellData(bkRow, "bkNo") == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);
            } else {
                let doRow3 = ds_containerDoorOrder.getRowPosition();
                if (doRow3 < 0 || ds_containerDoorOrder.getCellData(doRow3, "bkdoorseq") == "" || ds_containerDoorOrder.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Booking Door Order"]);
                } else {
                    ds_containerBookingCont.insertRow();
                    let bcRow = ds_containerBookingCont.getRowPosition();
                    ds_containerBookingCont.setCellData(bcRow, "kcomcd", scwin.hd_kcomcd);
                    ds_containerBookingCont.setCellData(bcRow, "bkNo", ds_containerBookingList.getCellData(bkRow, "bkNo"));
                    ds_containerBookingCont.setCellData(bcRow, "bkdoorseq", ds_containerDoorOrder.getCellData(doRow3, "bkdoorseq"));
                    ds_containerBookingCont.setCellData(bcRow, "inpid", scwin.userId);
                    gr_containerBookingCont.setFocusedCell(bcRow, "cntno");
                }
            }
            break;
    }
};

scwin.f_deleteRow = async function(disGubun) {
    switch (disGubun) {
        case 1:
            if (ds_containerDoorOrderQty.getRowCount() > 0 || ds_containerBookingCont.getRowCount() > 0) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Door Order Quantity Or Container", "delete"]);
            } else {
                let doRow = ds_containerDoorOrder.getRowPosition();
                if (doRow >= 0 && ds_containerDoorOrder.getCellData(doRow, "sendDt") != "") {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Order sended", "delete"]);
                } else if (doRow >= 0) {
                    ds_containerDoorOrder.removeRow(doRow);
                }
            }
            break;
        case 2:
            let dqRow = ds_containerDoorOrderQty.getRowPosition();
            if (dqRow >= 0) ds_containerDoorOrderQty.removeRow(dqRow);
            break;
        case 3:
            let bcRow = ds_containerBookingCont.getRowPosition();
            if (bcRow >= 0) ds_containerBookingCont.removeRow(bcRow);
            break;
    }
};

scwin.f_cancelRow = function(disGubun) {
    switch (disGubun) {
        case 1:
            ds_containerDoorOrder.undoAll();
            ds_containerDoorOrderQty.undoAll();
            break;
        case 2:
            ds_containerDoorOrderQty.undoAll();
            break;
        case 3:
            ds_containerBookingCont.undoAll();
            break;
    }
};

scwin.f_validate = async function() {
    if (scwin.tabIndex == 0) {
        if (!(await scwin.f_BookingTabValidate())) {
            return false;
        }
    } else if (scwin.tabIndex == 1) {
        if (!(await scwin.f_DoorOrderTabValidate())) {
            return false;
        }
    }
    return true;
};

scwin.f_BookingTabValidate = async function() {
    let chkValid = await $c.gus.cfValidate([ed_bkEtd, ed_bkEta]);
    if (!chkValid) {
        return false;
    }
    if (ed_bkEtd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETD"]);
        ed_bkEtd.setFocus();
        return false;
    }
    if (ed_bkEta.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETA"]);
        ed_bkEta.setFocus();
        return false;
    }
    if (!$c.gus.cfIsAfterDate(ed_bkEtd.getValue(), ed_bkEta.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETD", "ETA"]);
        ed_bkEtd.setFocus();
        return false;
    }
    if (!$c.gus.cfIsAfterDate(ica_ts1Eta.getValue(), ica_ts1Etd.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["T/S ETA", "T/S ETD"]);
        ica_ts1Eta.setFocus();
        return false;
    }
    if (!$c.gus.cfIsAfterDate(ica_ts2Eta.getValue(), ica_ts2Etd.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["T/S ETA", "T/S ETD"]);
        ica_ts2Eta.setFocus();
        return false;
    }
    if (!(await scwin.f_containerDualCheck())) return false;

    if (ed_cnttype1.getValue() != "") {
        let STR = scwin.f_containerTypeValueRow(ed_cnttype1.getValue());
        if (STR == "0") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            ed_cnttype1.setFocus();
            return false;
        }
    }
    if (ed_cnttype2.getValue() != "") {
        let STR = scwin.f_containerTypeValueRow(ed_cnttype2.getValue());
        if (STR == "0") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            ed_cnttype2.setFocus();
            return false;
        }
    }
    if (ed_cnttype3.getValue() != "") {
        let STR = scwin.f_containerTypeValueRow(ed_cnttype3.getValue());
        if (STR == "0") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            ed_cnttype3.setFocus();
            return false;
        }
    }
    if (ed_cnttype4.getValue() != "") {
        let STR = scwin.f_containerTypeValueRow(ed_cnttype4.getValue());
        if (STR == "0") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]);
            ed_cnttype4.setFocus();
            return false;
        }
    }
    let bkRow = ds_containerBookingList.getRowPosition();
    if (bkRow >= 0 && ds_containerBookingList.getCellData(bkRow, "custCd") == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
        return false;
    }
    let ctRow = ds_ctrtNo.getRowPosition();
    if ((ctRow >= 0 && ds_ctrtNo.getCellData(ctRow, "ctrtNo") == "선택") || lc_contractno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Contract No"]);
        return false;
    }
    if (bkRow >= 0 && ds_containerBookingList.getCellData(bkRow, "dept") == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Department"]);
        return false;
    }
    return true;
};

scwin.f_DoorOrderTabValidate = async function() {
    let msg = "[Booking] ";
    let chkValid = await $c.gus.cfValidate([gr_containerDoorOrder]);
    if (!chkValid) {
        return false;
    }
    if (ed_bkEtd.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "ETD"]);
        return false;
    }
    if (ed_bkEta.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "ETA"]);
        return false;
    }
    if (!$c.gus.cfIsAfterDate(ed_bkEtd.getValue(), ed_bkEta.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETD", "ETA"]);
        return false;
    }
    if (!(await scwin.f_containerDualCheck())) return false;

    if (ed_cnttype1.getValue() != "") {
        let STR = scwin.f_containerTypeValueRow(ed_cnttype1.getValue());
        if (STR == "0") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, [msg + "Container Type"]);
            return false;
        }
    }
    if (ed_cnttype2.getValue() != "") {
        let STR = scwin.f_containerTypeValueRow(ed_cnttype2.getValue());
        if (STR == "0") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, [msg + "Container Type"]);
            return false;
        }
    }
    if (ed_cnttype3.getValue() != "") {
        let STR = scwin.f_containerTypeValueRow(ed_cnttype3.getValue());
        if (STR == "0") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, [msg + "Container Type"]);
            return false;
        }
    }
    if (ed_cnttype4.getValue() != "") {
        let STR = scwin.f_containerTypeValueRow(ed_cnttype4.getValue());
        if (STR == "0") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, [msg + "Container Type"]);
            return false;
        }
    }
    let bkRow = ds_containerBookingList.getRowPosition();
    if (bkRow >= 0 && ds_containerBookingList.getCellData(bkRow, "custCd") == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Customer"]);
        return false;
    }
    let ctRow = ds_ctrtNo.getRowPosition();
    if ((ctRow >= 0 && ds_ctrtNo.getCellData(ctRow, "ctrtNo") == "선택") || lc_contractno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Contract No"]);
        return false;
    }
    if (bkRow >= 0 && ds_containerBookingList.getCellData(bkRow, "dept") == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, [msg + "Department"]);
        return false;
    }
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getRowStatus(i) != "D") {
            if (ds_containerDoorOrder.getRowCount() > 0) {
                if (ds_containerDoorOrderQty.getRowCount() == 0) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Qty"]);
                    return false;
                }
            }
        }
    }
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "bkdoorseq") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Seq"]);
            gr_containerDoorOrder.setFocusedCell(i, "bkdoorseq");
            return false;
        }
    }
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "doordt") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container Order Date"]);
            gr_containerDoorOrder.setFocusedCell(i, "doordt");
            return false;
        }
    }
    for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
        if (ds_containerDoorOrder.getCellData(i, "transcd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container Order Trucker"]);
            gr_containerDoorOrder.setFocusedCell(i, "transcd");
            return false;
        }
    }
    for (let i = 0; i < ds_containerDoorOrderQty.getRowCount(); i++) {
        if (ds_containerDoorOrderQty.getCellData(i, "qtytype") == "" && ds_containerDoorOrderQty.getCellData(i, "realQtytype") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Door Order Container Type"]);
            gr_containerDoorOrderQty.setFocusedCell(i, "qtytype");
            return false;
        }
    }
    return true;
};

scwin.f_containerTypeValueRow = function(val) {
    for (let i = 0; i < ds_containerType.getRowCount(); i++) {
        if (ds_containerType.getCellData(i, "CODE") == val) {
            return "1";
        }
    }
    return "0";
};

