scwin.f_containerDualCheck = async function() {
    let v_containerCheck = "0";
    if (ed_cnttype1.getValue() != "" && ed_cnttype2.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype2.getValue()) v_containerCheck = "1";
    if (ed_cnttype1.getValue() != "" && ed_cnttype3.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype3.getValue()) v_containerCheck = "1";
    if (ed_cnttype1.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype1.getValue() == ed_cnttype4.getValue()) v_containerCheck = "1";
    if (ed_cnttype2.getValue() != "" && ed_cnttype3.getValue() != "" && ed_cnttype2.getValue() == ed_cnttype3.getValue()) v_containerCheck = "1";
    if (ed_cnttype2.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype2.getValue() == ed_cnttype4.getValue()) v_containerCheck = "1";
    if (ed_cnttype3.getValue() != "" && ed_cnttype4.getValue() != "" && ed_cnttype3.getValue() == ed_cnttype4.getValue()) v_containerCheck = "1";
    if (v_containerCheck == "1") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container Type"]);
        return false;
    } else {
        return true;
    }
};

scwin.f_Print = function() {
    let odiParam = new ODIParam("se_101_01_01");
    odiParam.add("KCOMCD", scwin.hd_kcomcd);
    odiParam.add("BKNO", ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "bkNo"));
    odiParam.add("BKDOORSEQ", ds_containerDoorOrder.getCellData(ds_containerDoorOrder.getRowPosition(), "bkdoorseq"));
    odiParam.add("DEPTCD", ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "dept"));
    odiParam.add("USERID", scwin.userId);
    let formParam = new FormParam();
    let viewerParam = new ViewerParam();
    if (chb_pre.getValue() != "") {
        viewerParam.add("viewer.mode", "preview");
        viewerParam.add("print.mode", "print");
    } else {
        viewerParam.add("viewer.mode", "print");
        viewerParam.add("print.mode", "silent");
    }
    viewerParam.add("viewer.useprogressbar", "false");
    $c.gus.cfOZReport("", "chb_previewCheck", "/il/seaout/se_101_01_01.ozr", odiParam, viewerParam, formParam);
};

