scwin.f_doorTypeQtyLoading = function(row, colid) {
    let wgt = Number(ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "wgt")) / 1000;
    let msr = Number(ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "msr"));
    let qtytype = ds_containerDoorOrderQty.getCellData(row, "qtytype");
    if (qtytype == "WGT" || qtytype == "M/T") {
        ds_containerDoorOrderQty.setCellData(row, "qty", ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "wgt"));
    } else if (qtytype == "R/T") {
        if (wgt > msr) {
            ds_containerDoorOrderQty.setCellData(row, "qty", wgt);
        } else {
            ds_containerDoorOrderQty.setCellData(row, "qty", msr);
        }
    } else if (qtytype == "CBM") {
        ds_containerDoorOrderQty.setCellData(row, "qty", msr);
    } else {
        let bkRow = ds_containerBookingList.getRowPosition();
        if (bkRow >= 0) {
            if (qtytype == ds_containerBookingList.getCellData(bkRow, "cnttype1")) {
                ds_containerDoorOrderQty.setCellData(row, "qty", ds_containerBookingList.getCellData(bkRow, "cntqty1"));
            } else if (qtytype == ds_containerBookingList.getCellData(bkRow, "cnttype2")) {
                ds_containerDoorOrderQty.setCellData(row, "qty", ds_containerBookingList.getCellData(bkRow, "cntqty2"));
            } else if (qtytype == ds_containerBookingList.getCellData(bkRow, "cnttype3")) {
                ds_containerDoorOrderQty.setCellData(row, "qty", ds_containerBookingList.getCellData(bkRow, "cntqty3"));
            } else if (qtytype == ds_containerBookingList.getCellData(bkRow, "cnttype4")) {
                ds_containerDoorOrderQty.setCellData(row, "qty", ds_containerBookingList.getCellData(bkRow, "cntqty4"));
            }
        }
    }
};

