scwin.f_RunExcel = async function(dataId, gridId) {
    let countA = dataId.getRowCount();
    if (!(countA > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }
    let sheetName = "";
    let fileName = "";
    if (gridId == "gr_houseblList") {
        sheetName = "Booking List";
        fileName = "Booking List.xls";
    } else if (gridId == "gr_containerDoorOrder") {
        sheetName = "Door Order List";
        fileName = "Booking List.xls";
    }
    let chk = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (chk) {
        $c.data.downloadGridViewExcel(gridId, {fileName: fileName, sheetName: sheetName});
    }
};

scwin.f_openPgm = function(name) {
    if (name == "BookingFind") {
        let strPath = "/ui/il/seaout/sobk/se_103_01_01b.xml";
        $c.win.openMenu("Booking Search", strPath, "se_103_01_01b.xml", {hhio: scwin.hd_bkIo});
    } else if (name == "HouseBl") {
        let strPath = "/ui/il/seaout/sobl/se_105_01_01b.xml";
        $c.win.openMenu("Export House B/L", strPath, "se_105_01_01b.xml", {
            linkcheck: "4",
            kcomcd: scwin.hd_kcomcd,
            bkno: cnd_ed_bkNo.getValue(),
            carrierBkno: ed_carrierBkNo.getValue()
        });
    } else if (name == "DirectBl") {
        let strPath = "/ui/il/seaout/sobl/se_107_01_01b.xml";
        $c.win.openMenu("Direct B/L", strPath, "se_107_01_01b.xml", {
