scwin.sbm_retrieve_submitdone = async function(e) {
    if (ds_containerBookingList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
        scwin.f_Set("INIT");
        scwin.f_Check();
    } else {
        ed_totcnt.setValue(ds_containerBookingCont.getRowCount());
        let v_totPkg = 0;
        let v_totWgt = 0;
        let v_totMsr = 0;
        for (let i = 0; i < ds_containerBookingCont.getRowCount(); i++) {
            v_totPkg += Number(ds_containerBookingCont.getCellData(i, "cntpkg"));
            v_totWgt += Number(ds_containerBookingCont.getCellData(i, "cntwgt"));
            v_totMsr += Number(ds_containerBookingCont.getCellData(i, "cntmsrt"));
        }
        ed_totpkg.setValue(v_totPkg);
        ed_totwgt.setValue(v_totWgt);
        ed_totmsr.setValue(v_totMsr);
        scwin.f_Set("RETRIEVE");

        let bkRow = ds_containerBookingList.getRowPosition();
        if (bkRow >= 0 && ds_containerBookingList.getRowCount() > 0) {
            if (ds_containerBookingList.getCellData(bkRow, "contractno") != "") {
                scwin.v_contractno = ds_containerBookingList.getCellData(bkRow, "contractno");
                if (scwin.v_contractno == "NONE") {
                    scwin.f_ContractInfo();
                    ds_ctrtNo.removeAll();
                    ds_ctrtNo.insertRow();
                    ds_ctrtNo.setCellData(ds_ctrtNo.getRowPosition(), "ctrtNo", "NONE");
                    lc_contractno.setSelectedIndex(0);
                } else {
                    scwin.f_ContractInfo();
                }
            }
        }
    }
};

