scwin.ds_containerDoorOrder_onrowpositionchange = async function(rowIndex, oldRow) {
    if (rowIndex < 0) return;
    let v_kcomcd = ds_containerDoorOrder.getCellData(rowIndex, "kcomcd");
    let v_bkdoorseq = ds_containerDoorOrder.getCellData(rowIndex, "bkdoorseq");
    let v_bkNo = ds_containerDoorOrder.getCellData(rowIndex, "bkNo");

    if (rowIndex >= 0 && ds_containerDoorOrder.getRowStatus(rowIndex) != "C") {
        sbm_retrieveOrder.action = "/il.seaout.sobk.RetrieveContainerBookingOrderCMD.do?bkdoorseq=" + v_bkdoorseq + "&bkNo=" + v_bkNo + "&kcomcd=" + v_kcomcd;
        await $c.sbm.execute(sbm_retrieveOrder);
    } else if (ds_containerDoorOrder.getRowStatus(rowIndex) == "C") {
        let v_cnt = 0;
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getRowStatus(i) == "C") v_cnt++;
        }
        if (v_cnt == 1) {
            ds_containerDoorOrderQty.removeAll();
        }
    }
};

scwin.gr_containerDoorOrder_oneditend = async function(rowIndex, columnIndex, columnId, oldValue, newValue) {
    if (rowIndex >= 0 && ds_containerDoorOrder.getRowCount() > rowIndex) {
        switch (columnId) {
            case "transcd":
                if (ds_containerDoorOrder.getCellData(rowIndex, columnId).trim() != "") {
                    if (ds_containerDoorOrder.getCellData(rowIndex, "internalTyp") == "1") {
                        ds_containerDoorOrder.setCellData(rowIndex, "transnm", "");
                        scwin.f_PopUpGrid("Department", rowIndex, "T");
                    } else {
                        ds_containerDoorOrder.setCellData(rowIndex, "transnm", "");
                        scwin.f_PopUpGrid("Customer", rowIndex, "T");
                    }
                } else {
                    ds_containerDoorOrder.setCellData(rowIndex, "transcd", "");
                    ds_containerDoorOrder.setCellData(rowIndex, "transnm", "");
                }
                break;
            case "fcity":
                if (ds_containerDoorOrder.getCellData(rowIndex, columnId).trim() != "") {
                    ds_containerDoorOrder.setCellData(rowIndex, "fcitynm", "");
                    scwin.f_PopUpGrid("PickupCy", rowIndex, "T");
                } else {
                    ds_containerDoorOrder.setCellData(rowIndex, "fcity", "");
                    ds_containerDoorOrder.setCellData(rowIndex, "fcitynm", "");
                }
                break;
            case "doorcd":
                if (ds_containerDoorOrder.getCellData(rowIndex, columnId).trim() != "") {
                    ds_containerDoorOrder.setCellData(rowIndex, "doornm", "");
                    scwin.f_PopUpGrid("Door", rowIndex, "T");
                } else {
                    ds_containerDoorOrder.setCellData(rowIndex, "doorcd", "");
                    ds_containerDoorOrder.setCellData(rowIndex, "doornm", "");
                }
                break;
            case "tcity":
                if (ds_containerDoorOrder.getCellData(rowIndex, columnId).trim() != "") {
                    ds_containerDoorOrder.setCellData(rowIndex, "tcitynm", "");
                    scwin.f_PopUpGrid("GateinCy", rowIndex, "T");
                } else {
                    ds_containerDoorOrder.setCellData(rowIndex, "tcity", "");
                    ds_containerDoorOrder.setCellData(rowIndex, "tcitynm", "");
                }
                break;
        }
    }
};

scwin.gr_containerDoorOrder_onheaderclick = function(columnIndex, columnId) {
    if (columnId == "chk") {
        let allChecked = true;
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "sendDt") == "" && ds_containerDoorOrder.getCellData(i, "chk") != "T") {
                allChecked = false;
                break;
            }
        }
        for (let i = 0; i < ds_containerDoorOrder.getRowCount(); i++) {
            if (ds_containerDoorOrder.getCellData(i, "sendDt") == "") {
                ds_containerDoorOrder.setCellData(i, "chk", allChecked ? "F" : "T");
            }
        }
    }
};

