scwin.gr_containerDoorOrder_onexit_seqcheck = async function(rowIndex, columnIndex, columnId) {
    for (let i = 0; i < ds_containerDoorOrder.getRowCount() - 1; i++) {
        for (let j = i + 1; j < ds_containerDoorOrder.getRowCount(); j++) {
            if (ds_containerDoorOrder.getCellData(i, "bkdoorseq") == ds_containerDoorOrder.getCellData(j, "bkdoorseq")) {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container Seq"]);
                gr_containerDoorOrder.setFocusedCell(j, "bkdoorseq");
                return;
            }
        }
    }
};

scwin.gr_containerDoorOrderQty_onexit_typecheck = async function(rowIndex, columnIndex, columnId) {
    if (columnId == "qtytype") {
        for (let i = 0; i < ds_containerDoorOrderQty.getRowCount() - 1; i++) {
            for (let j = i + 1; j < ds_containerDoorOrderQty.getRowCount(); j++) {
                if (ds_containerDoorOrderQty.getCellData(i, "qtytype") == ds_containerDoorOrderQty.getCellData(j, "qtytype")) {
                    await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container Type"]);
                    gr_containerDoorOrderQty.setFocusedCell(j, "qtytype");
                    return;
                }
            }
        }
    }
};

