scwin.lc_contractno_ondropdown = async function() {
    scwin.v_contractno = "";
    if (ed_bkEtd.getValue() == "" || ed_bkEtd.getValue() == null) {
        await $c.win.alert("ETD is mandatory to retrieve Contract No");
        ds_ctrtNo.removeAll();
        ed_salesCd.setValue("");
        txt_salesNm.setValue("");
        return false;
    } else {
        await scwin.f_ContractInfo();
        if (scwin.statusFlag == "C" || scwin.statusFlag == "U") {
            if (ds_ctrtNo.getRowCount() == 0) ds_ctrtNo.insertRow();
            let ctRow = ds_ctrtNo.getRowPosition();
            if (ctRow >= 0 && ds_ctrtNo.getCellData(ctRow, "empNo") != "") {
                if (ed_salesCd.getValue() == "") {
                    ed_salesCd.setValue(ds_ctrtNo.getCellData(ctRow, "empNo"));
                    scwin.f_OpenCommonPopUp("Salesman", "T", "F", "F");
                }
            }
        }
    }
};

